#include &lt;bits/stdc++.h&gt;using namespace std;int cti(char c)&#123;		//單一羅馬數字轉數字	switch(c)&#123;		case &#x27;I&#x27;: return 1;		case &#x27;V&#x27;: return 5;		case &#x27;X&#x27;: return 10;		case &#x27;L&#x27;: return 50;		case &#x27;C&#x27;: return 100;		case &#x27;D&#x27;: return 500;		case &#x27;M&#x27;: return 1000;		default : return 0;	&#125;&#125;int rti(string s)&#123;		//分解羅馬數字並判斷加減	int p=0,ans=0;		//p為上一位數	for(char c:s)&#123;		int n=cti(c);		ans+=n;		if(n&gt;p)			ans-=2*p;	//MCM		p=n;			&#125;	return ans;&#125;string itr(int n)&#123;		//數字轉羅馬	if(n==0)		return &quot;ZERO&quot;;		int v[]=   &#123;1000, 900, 500, 400, 100, 90 , 50, 40 , 10,  9 , 5 , 4  ,  1&#125;;    string s[]=&#123;&quot;M&quot; ,&quot;CM&quot;, &quot;D&quot;,&quot;CD&quot;, &quot;C&quot;,&quot;XC&quot;,&quot;L&quot;,&quot;XL&quot;,&quot;X&quot;,&quot;IX&quot;,&quot;V&quot;,&quot;IV&quot;,&quot;I&quot;&#125;;        string ans=&quot;&quot;;    for(int i=0;i&lt;13;i++)&#123;    	while(n&gt;=v[i])&#123;		//重複減直到小於當前檢查的數字    		n-=v[i];    		ans+=s[i];		&#125;	&#125;	return ans;&#125;int main()&#123;	string s;	while(getline(cin,s) &amp;&amp; s!=&quot;#&quot;)&#123;		string f=&quot;&quot;,t=&quot;&quot;;		for(int i=0;i&lt;s.length();i++)&#123;		 	if(s[i]==&#x27; &#x27;)&#123;		 		for(int j=i+1;j&lt;s.length();j++)		 			t+=s[j];		 		break;			&#125;else				f+=s[i];		&#125;		cout &lt;&lt; itr(abs(rti(t)-rti(f))) &lt;&lt; &#x27;\n&#x27;;	&#125;	return 0;&#125;

