a017. 五則運算題目網址:https://zerojudge.tw/ShowProblem?problemid=a017解題觀念:變數運算、轉換、迴圈控制
#include &lt;bits/stdc++.h&gt;using namespace std;//解無括號之算式 long long slove(string s)&#123;		//https://www.runoob.com/cplusplus/cpp-libs-sstream.html	stringstream ss(s);		//暫存器 	string a;	vector&lt;long long&gt; v;	//運算元儲存器 	vector&lt;string&gt; c;		//運算子儲存器		//字串拆分 	while(ss &gt;&gt; a)&#123;		if(isdigit(a[0]) || (a.length()&gt;1 &amp;&amp; a[0]==&#x27;-&#x27;))			v.push_back(stoll(a));		else			c.push_back(a);	&#125;		// * / % 先計算 	for(int i=0;i&lt;c.size();i++)&#123;		if(c[i]==&quot;*&quot;)&#123;			c.erase(c.begin()+i);			v[i]*=v[i+1];			v.erase(v.begin()+i+1);						//避免因前一元素擦除而忽略元素或溢位			i--; 		&#125;else if(c[i]==&quot;/&quot;)&#123;			c.erase(c.begin()+i);			v[i]/=v[i+1];			v.erase(v.begin()+i+1);			i--;		&#125;else if(c[i]==&quot;%&quot;)&#123;			c.erase(c.begin()+i);			v[i]%=v[i+1];			v.erase(v.begin()+i+1);			i--;		&#125;	&#125;		// + - 後處理 	for(int i=0;i&lt;c.size();i++)&#123;		if(c[i]==&quot;+&quot;)&#123;			c.erase(c.begin()+i);			v[i]+=v[i+1];			v.erase(v.begin()+i+1);			i--;		&#125;else if(c[i]==&quot;-&quot;)&#123;			c.erase(c.begin()+i);			v[i]-=v[i+1];			v.erase(v.begin()+i+1);			i--;		&#125;	&#125;		//回傳解 	return v[0];&#125;//含有括號的算式處理 long long re_slove(string s)&#123;	while(1)&#123;				//左右括號索引暫存器		int l=-1,r=-1;				//尋找一對括號 		for(int i=0;i&lt;s.length();i++)&#123;			if(s[i]==&#x27;(&#x27;)				l=i;			else if(s[i]==&#x27;)&#x27;)&#123;				r=i;				break;			&#125;			&#125;				//未找到則跳出迴圈 		if(l==-1)			break;					//找到則計算並替換原有括號處 		long long m=slove(s.substr(l+1,r-l));		s.replace(l,r-l+1,to_string(m));	&#125;	return slove(s);&#125;int main()&#123;	string s;	while(getline(cin,s))		cout &lt;&lt; re_slove(s) &lt;&lt; &#x27;\n&#x27;;	return 0;&#125;

a020. 身分證檢驗題目網址:https://zerojudge.tw/ShowProblem?problemid=a020解題觀念:基礎邏輯判斷、變數運算
#include &lt;bits/stdc++.h&gt;using namespace std;int main()&#123;	string s;	int t=0;	cin &gt;&gt; s;		if(s[0]==&#x27;I&#x27;)		t=34;	else if(s[0]==&#x27;O&#x27;)		t=35;	else if(s[0]==&#x27;W&#x27;)		t=32;	else if(s[0]==&#x27;X&#x27;)		t=30;	else if(s[0]==&#x27;Y&#x27;)		t=31;	else if(s[0]==&#x27;Z&#x27;)		t=33;	else if(s[0]&gt;=&#x27;A&#x27; &amp;&amp; s[0]&lt;=&#x27;H&#x27;)		t=s[0]-&#x27;A&#x27;+10;	else if(s[0]&gt;=&#x27;J&#x27; &amp;&amp; s[0]&lt;=&#x27;N&#x27;)		t=s[0]-&#x27;J&#x27;+18;	else if(s[0]&gt;=&#x27;P&#x27; &amp;&amp; s[0]&lt;=&#x27;V&#x27;)		t=s[0]-&#x27;P&#x27;+23;	t=(t%10)*9+t/10;		for(int i=1;i&lt;s.length()-1;i++)		t+=(s[i]-&#x27;0&#x27;)*(9-i);	t+=s[s.length()-1]-&#x27;0&#x27;;		if(t%10==0)		cout &lt;&lt; &quot;real\n&quot;;	else		cout &lt;&lt; &quot;fake\n&quot;;	return 0;&#125;


a021. 大數運算題目網址:https://zerojudge.tw/ShowProblem?problemid=a021解題觀念:變數運算、陣列應用、函式運用
#include &lt;bits/stdc++.h&gt;using namespace std;//a&lt;b回傳 -1; a&gt;b回傳 1; 一樣回傳0;int compare(string a, string b)&#123; 	if(a.length()&gt;b.length())		return 1;	if(a.length()&lt;b.length())		return -1;	if(a&gt;b)		return 1;	if(a&lt;b)		return -1;	return 0;	&#125;//加法 string pluss(string a, string c)&#123;	string ans=&quot;&quot;;	int p=0;	//進位計數器		//始終以 a 為較大者 	if(compare(c,a)&lt;0)		swap(a,c);			reverse(a.begin(),a.end());	reverse(c.begin(),c.end());	for(int i=0;i&lt;a.length();i++)&#123;		int n=a[i]-&#x27;0&#x27;+p;				//如果已超過 c 的位數則忽略 c 		if(i&lt;c.length())			n+=(c[i]-&#x27;0&#x27;);		ans+=n%10+&#x27;0&#x27;;		p=n/10;	&#125;		//若計數器有殘餘則加回 	if(p!=0)		ans+=p+&#x27;0&#x27;;			reverse(ans.begin(),ans.end());	return ans;&#125;//乘法 (直式乘法)string cross(string a, string c)&#123;	string ans=&quot;&quot;;	vector&lt;int&gt; v(a.length()+c.length(),0);	//直式位數暫存器 	reverse(a.begin(),a.end());	reverse(c.begin(),c.end());		//直式乘法 	for(int i=0;i&lt;c.length();i++)&#123;		for(int j=0;j&lt;a.length();j++)&#123;			int n=(a[j]-&#x27;0&#x27;)*(c[i]-&#x27;0&#x27;);			v[j+i]+=n;		&#125;	&#125;		//進位處理 	int p=0;	for(int i=0;i&lt;v.size();i++)&#123;		int c=v[i]+p;		ans+=c%10+&#x27;0&#x27;;		p=c/10;	&#125;		//殘餘進位補回 	while(p)&#123;		ans+=p%10+&#x27;0&#x27;;		p/=10;	&#125;		//去除可能出現在首位的 0	while (ans.size()&gt;1 &amp;&amp; ans.back()==&#x27;0&#x27;)        ans.pop_back();		reverse(ans.begin(),ans.end());	return ans;&#125;//減法 (輸入前須做大小檢查，前者需為較大者)string minuss(string a, string c)&#123;	string ans=&quot;&quot;;	reverse(a.begin(),a.end());	reverse(c.begin(),c.end());		int m=0;	//借位暫存器 		//以較短位數為目標施行減法	for(int i=0;i&lt;c.length();i++)&#123; 		int n=(a[i]-&#x27;0&#x27;)-(c[i]-&#x27;0&#x27;)-m;		if(n&lt;0)&#123;			m=1;			n+=10;		&#125;else			m=0;		ans+=n%10+&#x27;0&#x27;;	&#125;		//補回較長者剩餘位數	for(int i=c.length();i&lt;a.length();i++)&#123; 		int n=(a[i]-&#x27;0&#x27;)-m;		if(n&lt;0)&#123;			m=1;			n+=10;		&#125;else			m=0;			ans+=n%10+&#x27;0&#x27;;	&#125;	reverse(ans.begin(), ans.end());		//去除可能出現在首位的 0 	while(ans.length()&gt;1 &amp;&amp; ans[0]==&#x27;0&#x27;)       	ans.erase(0, 1);	return ans;&#125;//除法 (長除法)string divded(string a, string c)&#123;	if(compare(a,c)&lt;0)		return &quot;0&quot;;	string ans=&quot;0&quot;;	string q=&quot;&quot;;	//被除數 			for(int i=0;i&lt;a.length();i++)&#123;				q+=a[i];	//一次取一位				//去除可能出現在首位的 0 		while(q.length()&gt;1 &amp;&amp; q[0]==&#x27;0&#x27;)            q.erase(0, 1);                //商數計數器 		int n=0;				//以減法取代除法		while(compare(q,c)&gt;=0)&#123; 			q=minuss(q,c);			n++;		&#125;		ans+=n+&#x27;0&#x27;;	&#125;		//去除可能出現在首位的 0 	while(ans.length() &gt; 1 &amp;&amp; ans[0]==&#x27;0&#x27;)        ans.erase(0, 1);    return ans;&#125;int main()&#123;	string s,a,b,c;	getline(cin,s);	stringstream ss(s);	//https://www.runoob.com/cplusplus/cpp-libs-sstream.html	ss &gt;&gt; a &gt;&gt; b &gt;&gt; c;	//分離 數字(a,c)及運算子(c)		if(b==&quot;+&quot;)&#123;		cout &lt;&lt; pluss(a,c) &lt;&lt; &#x27;\n&#x27;;	&#125;else if(b==&quot;*&quot;)&#123;		cout &lt;&lt; cross(a,c) &lt;&lt; &#x27;\n&#x27;;	&#125;else if(b==&quot;-&quot;)&#123;		if(compare(a,c)&lt;0)			cout &lt;&lt; &#x27;-&#x27; &lt;&lt; minuss(c,a) &lt;&lt; &#x27;\n&#x27;;		else			cout &lt;&lt; minuss(a,c) &lt;&lt; &#x27;\n&#x27;;	&#125;else if(b==&quot;/&quot;)&#123;		cout &lt;&lt; divded(a,c) &lt;&lt; &#x27;\n&#x27;;	&#125;	return 0;&#125;

